const ItemInfoView  = ({ item, show, hidde }) => {


	let height = show ? ObjectKeys(item?.packages).length * 60 + 90 : 0;

	return (

		
		
		<div className={` content_show ${show?"show":""} `} style={{height}} >
			<div style={{paddingTop: 30}}/>

			{item?.packages && ObjectKeys(item?.packages).map((pckId, pckIndx)=>{
				let weLb = (item?.packages?.[pckId]?.weight*1).toFixed(2);

				let deliveryId = item?.packages?.[pckId]?.serviceType?.id;
				let deliveryIcon = deliveryId === "MLOH"? "rocket-launch-outline": deliveryId === "AV1X"? "airplane": deliveryId === "EX2MA"? "ferry":"";
				
				return (
					<div className="_dsplFlx package_detail_box" key={"package_"+pckId} >
						<div className="total_pck" style={{marginLeft: 9}}>
							{pckIndx + 1}
						</div>
						<div  className="icon blue30" >
							<Svg name={"open_package_file_outline"}	/>
						</div>
						<div className="lbl_tx tr_bar_20 tex_aleft">
							{pckId}
						</div>
						<div className="flexSpace"/>
						<div  className="icon blue30"  style={{marginLeft: 32}} >
							<Svg name={"weight-pound"}	/>
						</div>
						<div className="lbl_tx">
							{weLb}
						</div>
						{!getStore("isMobile")?
						<>
							<div className="flexSpace"/>
							<div  className="icon blue30" style={{marginLeft: 32}} >
								<Svg name={deliveryIcon}	/>
							</div>
							<div className="lbl_tx tr_bar_20 tex_aleft" style={{marginLeft: 2}}>
								{item?.packages?.[pckId]?.serviceType?.label}
							</div>
						</>:null }
					</div>
				)
			})}
			
		<div>
		<div style={{paddingTop: 30}}/>
		<div className="_dsplFlx package_detail_box" >
			<div className="flexSpace"/>
			{show?
			<div className="" onClick={()=>hidde(!show)}>
					<Svg 
						name={"key_arrow_up"} 
						color={"var(--primary-blue--backg-30)"}
						size={24}
					/>
			</div>
			:null}
			<div className="flexSpace"/>
		</div>
		</div>
	</div>

	)
}










